fragBody:
vec3 n = normalize(v_normal);
vec3 viewDir = normalize(-v_worldPos);
vec3 lightDir = normalize(vec3(1.0, 1.0, 1.0));

// Ambient spooky blue
vec3 ambient = vec3(0.1, 0.05, 0.2) * 0.5;

// Main directional light (brass lantern feel)
float diff = max(dot(n, lightDir), 0.0);
vec3 diffuse = vec3(1.0, 0.8, 0.4) * diff;

// Specular highlight
float spec = pow(max(dot(reflect(-lightDir, n), viewDir), 0.0), 32.0);
vec3 specular = vec3(1.0) * spec * 0.4;

// Base color mixing
vec3 base = v_baseColor;
vec3 color = ambient + diffuse * base + specular * base;

// Add a subtle "spirit" glow if the object is moving or has a specific color tag
if (base.r > 0.8 && base.g < 0.2) {
    color += vec3(0.4, 0.6, 1.0) * (0.5 + 0.5 * sin(u_time * 10.0 + v_worldPos.x * 5.0));
}

// Distance fog (indigo)
float dist = length(v_worldPos);
float fog = smoothstep(3.0, 8.0, dist);
vec3 fogColor = vec3(0.05, 0.02, 0.1);
color = mix(color, fogColor, fog);

fragColor = vec4(color, 1.0);

