state.draws = [];

function addPart(p, pos, rot, s, col) {
    state.draws.push({ prim: p, pos: pos, rot: rot, scale: s, color: col });
}

let engineColor = [0.8, 0.1, 0.1];
let brassColor = [0.9, 0.7, 0.2];
let smokeColor = [0.4, 0.4, 0.5];

addPart("cylinder", [0, 1.5, 2.0], [0, 0, 0], 1.5, smokeColor);
addPart("cylinder", [0, 1.5, 0.5], [0, 0, 0], 0.6, engineColor);
addPart("plane", [0, 1.5, 3.2], [0, 0, 0], [0.5, 0.5, 2.0], smokeColor);

addPart("cube", [0, 0.5, -2.5], [0, 0, 0], 1.8, [0.3, 0.2, 0.4]);
addPart("cube", [0.0, 1.5, -2.8], [0, 0, 0], 1.6, [0.3, 0.2, 0.4]);

let axles = [1.5, 4.5, 7.5];
axles.forEach((z, i) => {
    addPart("cylinder", [axleOffset, 0.5, z], [Math.PI/2, 0, wheelRot], [wheelRadius, 0.3, wheelRadius], engineColor);
    addPart("cylinder", [-axleOffset, 0.5, z], [Math.PI/2, 0, wheelRot], [wheelRadius, 0.3, wheelRadius], engineColor);
    addPart("cylinder", [axleOffset, 0.5, z], [Math.PI/2, 0, wheelRot - 0.5], [wheelRadius * 1.05, 0.05, wheelRadius * 1.05], brassColor);
    addPart("cylinder", [-axleOffset, 0.5, z], [Math.PI/2, 0, wheelRot - 0.5], [wheelRadius * 1.05, 0.05, wheelRadius * 1.05], brassColor);
    if (i < 2) {
        let dist = axles[i+1] - z;
        addPart("cylinder", [axleOffset, 0.5, z + dist/2], [0, 0, Math.PI/2], [dist, 0.1, 0.1], brassColor);
