fragBody:
vec3 n = normalize(v_normal);
vec3 viewDir = normalize(-v_worldPos);
vec3 lightDir = normalize(vec3(1.0, 2.0, 1.5));

// Toon shading
float diff = max(dot(n, lightDir), 0.0);
vec3 base = v_baseColor;
vec3 shade = base * diff;

// Hard bands for toon effect
if (diff < 0.2) shade *= 0.4;
else if (diff < 0.5) shade *= 0.7;
else shade *= 1.0;

// Fresnel rim light for "grime"
float rim = pow(1.0 - max(dot(n, viewDir), 0.0), 3.0);
vec3 rimColor = vec3(0.1, 0.15, 0.05) * rim * 1.5;

// Outline approximation via depth discontinuity (simplified here via normal/view angle)
float outline = 1.0 - max(dot(n, viewDir), 0.0);
vec3 finalColor = mix(shade + rimColor, vec3(0.0), outline * 0.4);

// Slight vignette based on world position distance
float dist = length(v_worldPos);
finalColor *= 1.0 - smoothstep(2.5, 4.0, dist) * 0.5;

fragColor = vec4(finalColor, 1.0);

