vec3 lightDir = normalize(vec3(0.5, 1.0, 0.5));
vec3 viewDir = normalize(vec3(0.0, 0.0, 1.0)); // Simplified view dir

// Ambient
vec3 albedo = v_baseColor;
float amb = 0.15;

// Diffuse
float diff = max(dot(N, lightDir), 0.0);
diff = 0.8 * diff;

// Specular (Phong)
vec3 reflectDir = reflect(-lightDir, N);
float spec = pow(max(dot(viewDir, reflectDir), 0.0), 32.0);
spec = 0.4 * spec;

// Blueprint Glow Effect based on height/depth
float depthGlow = 0.0;
if (v_worldPos.y < -0.2) {
    depthGlow = 0.3;
}

vec3 finalColor = albedo * (amb + diff) + vec3(spec) + vec3(0.2, 0.6, 0.9) * depthGlow;

// Add subtle scanline pattern for "old monitor/blueprint" feel
float scan = sin(v_worldPos.y * 40.0 - u_time * 2.0) * 0.05 + 0.5;
finalColor *= mix(0.9, 1.1, scan);

fragColor = vec4(finalColor, 1.0);

