state.bg = [0.05, 0.02, 0.02]; // Deep sepia/dark red
const time = t;
const speed = 0.0005;

// Central Operating Table
state.draws.push({
    prim: "plane", pos: [0, 0.5, 0], rot: [0, 0, 0], scale: [1.2, 0.01, 2.0], color: [0.1, 0.3, 0.1] // Sheet
});
state.draws.push({
    prim: "cylinder", pos: [0, 0.2, 0], rot: [Math.PI/2, 0, 0], scale: [0.3, 2.0, 0.3], color: [0.2, 0.1, 0.0] // Patient body
});
state.draws.push({
    prim: "sphere", pos: [0, 0.6, 0], scale: 0.15, color: [0.2, 0.1, 0.0] // Head
});

// Surgeons Ring
const surgeonCount = 6;
for (let i = 0; i < surgeonCount; i++) {
    const angle = (i / surgeonCount) * Math.PI * 2;
    const dist = 2.5;
    const px = Math.cos(angle) * dist;
    const pz = Math.sin(angle) * dist;

    // Torso
    state.draws.push({
        prim: "cylinder", pos: [px, 1.0, pz], scale: [0.3, 1.8, 0.3], rot: [0, angle + Math.PI, 0], color: [0.1, 0.1, 0.1]
    });
    // Head/Top Hat
    state.draws.push({
        prim: "sphere", pos: [px, 2.0, pz], scale: 0.2, color: [0.9, 0.8, 0.6]
    });
    state.draws.push({
        prim: "cylinder", pos: [px, 2.25, pz], scale: [0.2, 0.2, 0.2], color: [0.0, 0.0, 0.0]
    });
    // Instruments (Scalpel in hand)
    state.draws.push({
        prim: "cylinder", pos: [px + Math.cos(angle+1.5)*0.2, 1.2, pz + Math.sin(angle+1.5)*0.2], 
        scale: [0.02, 0.4, 0.02], rot: [Math.PI/2, angle, 0], color: [0.8, 0.8, 0.8]
    });
}

// Tiered Audience Gallery
const ringCount = 3;
for (let r = 0; r < ringCount; r++) {
    const rowDist = 4.0 + r * 1.5;
    const rowY = 2.0 + r * 1.0;
    const people = 8 + r * 4;

    // Platform for this row
    state.draws.push({
        prim: "torus", pos: [0, rowY, 0], scale: [rowDist, 0.05, rowDist], color: [0.15, 0.15, 0.15]
    });

    for (let i = 0; i < people; i++) {
        const angle = (i / people) * Math.PI * 2;
        const px = Math.cos(angle) * rowDist;
        const pz = Math.sin(angle) * rowDist;

        // Head
        state.draws.push({
            prim: "sphere", pos: [px, rowY + 0.3, pz], scale: 0.1, color: [0.8, 0.7, 0.6]
        });
    }
}

// Floating Instruments (Exploded View elements)
state.draws.push({
    prim: "cone", pos: [-2.5, 3.0, 0], scale: 0.5, rot: [Math.PI/2, 0, 0], color: [0.9, 0.5, 0.5] // Scalpel blade abstract
});
state.draws.push({
    prim: "torus", pos: [2.5, 3.0, 0], scale: [0.3, 0.3, 0.1], color: [0.5, 0.5, 0.9] // Anesthesia bowl
});
state.draws.push({
    prim: "cube", pos: [0, 4.0, -3.0], scale: 0.8, color: [0.4, 0.4, 0.4] // Medicine cabinet
});

fragBody:
vec3 n = normalize(v_normal);
vec3 lightDir = normalize(vec3(1.0, 1.0, 1.5));
float diffuse = max(dot(n, lightDir), 0.2);

// Clay-like soft lighting with high ambient
vec3 base = v_baseColor;
vec3 litColor = base * (0.4 + 0.6 * diffuse);

// Fresnel rim for that clay look
float rim = pow(1.0 - max(dot(n, vec3(0.0, 0.0, 1.0)), 0.0), 2.5);
litColor += vec3(1.0) * rim * 0.8;

// Animate liquids in jars (identified by green hue in base color)
if (v_baseColor.g > 0.6 && v_baseColor.r < 0.3) {
    float swirl = sin(v_worldPos.x * 3.0 + u_time * 2.0) * 0.1;
    litColor.r += swirl;
    litColor.b -= swirl;
}

fragColor = vec4(litColor, 1.0);

