fragBody:
vec3 n = normalize(v_normal);
vec3 lightDir = normalize(vec3(0.5, 1.0, 0.7));
float diff = max(dot(n, lightDir), 0.0);

// Cel-shaded steps
float shade = step(0.1, diff) * 0.3 + step(0.3, diff) * 0.3 + step(0.6, diff) * 0.4;
float ambient = 0.25;
vec3 base = v_baseColor;

// Add a subtle metallic rim for the porcelain
vec3 viewDir = normalize(-v_worldPos); // Approximate view from center
float fresnel = pow(1.0 - max(dot(n, viewDir), 0.0), 3.0);
vec3 rim = vec3(0.9, 0.8, 0.6) * fresnel * 0.5;

// Depth-based fog for the exploded feel
float dist = length(v_worldPos);
float fogFactor = clamp(dist * 0.1, 0.0, 0.8);

vec3 finalColor = mix(base, vec3(0.15, 0.12, 0.18), fogFactor);
finalColor += (base * shade) + (base * ambient) + rim;

// Soft outline based on normals vs view (fake outline)
float outline = smoothstep(0.8, 1.0, 1.0 - max(dot(n, viewDir), 0.0));
finalColor = mix(finalColor, vec3(0.0, 0.0, 0.0), outline * 0.4);

fragColor = vec4(finalColor, 1.0);

