state.bg = [0.15, 0.05, 0.05];
const frameTime = t % 30;
const wingSpeed = frameTime * 0.5;

function addGear(p, s, c, r) {
    const teeth = 12;
    for (let i = 0; i < teeth; i++) {
        const angle = (i / teeth) * Math.PI * 2 + r;
        const x = Math.cos(angle) * s * 1.2;
        const z = Math.sin(angle) * s * 1.2;
        state.draws.push({
            prim: "cube",
            pos: [p[0] + x, p[1], p[2] + z],
            scale: [s * 0.2, s, s * 0.2],
            rot: [0, angle + Math.PI/2, 0],
            color: c
        });
    }
    state.draws.push({ prim: "torus", pos: p, scale: s, color: c });
}

state.draws.push({ prim: "cylinder", pos: [0, 0, 0], scale: [0.4, 1.2, 0.4], color: [0.8, 0.7, 0.3], rot: [0, 0, 0] });
state.draws.push({ prim: "cone", pos: [0, 0.8, 0.4], scale: 0.3, color: [0.6, 0.4, 0.2], rot: [Math.PI/2, 0, 0] });
state.draws.push({ prim: "sphere", pos: [-0.1, 0.8, 0.2], scale: 0.35, color: [0.9, 0.9, 0.9], rot: [0,0,0] });

addGear([0, 0.4, 0.42], 0.4, [0.4, 0.3, 0.1], frameTime * 0.1);
addGear([0, -0.4, 0.42], 0.35, [0.4, 0.3, 0.1], -frameTime * 0.1);

const w1 = Math.sin(wingSpeed) * 0.5;
const w2 = Math.cos(wingSpeed) * 0.5;
state.draws.push({ prim: "cube", pos: [-0.8, 0.2, w1], scale: [1.5, 0.1, 0.1], color: [0.9, 0.9, 0.9], rot: [0, 0, w2] });
state.draws.push({ prim: "plane", pos: [-1.0, 0.3, w1], scale: [1.8, 1.0, 1.0], color: [0.2, 0.6, 0.8], rot: [0, 0, w2] });
state.draws.push({ prim: "cube", pos: [0.8, 0.2, w1], scale: [1.5, 0.1, 0.1], color: [0.9, 0.9, 0.9], rot: [0, 0, w2] });
state.draws.push({ prim: "plane", pos: [1.0, 0.3, w1], scale: [1.8, 1.0, 1.0], color: [0.2, 0.6, 0.8], rot: [0, 0, w2] });
state.draws.push({ prim: "cone", pos: [0, -0.8, -0.4], scale: 0.5, color: [0.3, 0.2, 0.1], rot: [-Math.PI/2, 0, 0] });

for(let i=0; i<5; i++) {
    const tx = (Math.random() - 0.5) * 3;
    const ty = (Math.random() - 0.5) * 3;
    const tz = (Math.random() - 0.5) * 3;
    state.draws.push({ prim: "cylinder", pos: [tx, ty, tz], scale: [0.05, 0.5, 0.05], color: [1.0, 1.0, 1.0], rot: [0, frameTime + i, 0] });
}

