state.bg = [0.02, 0.05, 0.06];
state.camera = { eye: [0, 2, 8], target: [0, 0, 0], up: [0, 1, 0] };

const time = t % 30;

const ratBodyColor = [0.15, 0.25, 0.25];
const ratEyeColor = [0.8, 0.4, 1.0];
const brickColor = [0.4, 0.15, 0.1];
const waterColor = [0.05, 0.15, 0.1];

const draws = [];

draws.push({
    prim: "plane", pos: [0, -1.0, 0], scale: [4.0, 1.0, 10.0], color: waterColor
});

draws.push({
    prim: "plane", pos: [-2.0, 0.0, 0], rot: [0, Math.PI/2, 0], scale: [4.0, 4.0, 0.5], color: brickColor
});
draws.push({
    prim: "plane", pos: [2.0, 0.0, 0], rot: [0, -Math.PI/2, 0], scale: [4.0, 4.0, 0.5], color: brickColor
});

for (let i = 0; i < 6; i++) {
    draws.push({
        prim: "cube", pos: [-2.5, i*0.5 - 1.0, 0], rot: [0, Math.PI/2, 0], scale: [0.2, 0.4, 0.4], color: [0.3, 0.1, 0.1]
    });
    draws.push({
        prim: "cube", pos: [2.5, i*0.5 - 1.0, 0], rot: [0, -Math.PI/2, 0], scale: [0.2, 0.4, 0.4], color: [0.3, 0.1, 0.1]
    });
}

let tailPos = -1.5;
const numTailSegments = 25;
const tailLength = 4.0;
const tailAmplitude = 0.6;

for (let i = 0; i < numTailSegments; i++) {
    const segT = i / numTailSegments;
    const x = tailPos + segT * tailLength;
    const y = Math.sin(segT * Math.PI * 2 + time * 2.0) * tailAmplitude * (1.0 - segT);
    const scale = 0.8 - segT * 0.7;

    draws.push({
        prim: "torus", pos: [x, y, 0], scale: [scale * 0.15, scale * 0.15, 0.2], color: [0.4, 0.4, 0.4]
    });
}

const bodyY = 0.5;
draws.push({ prim: "sphere", pos: [0, bodyY, 0], scale: 1.2, color: ratBodyColor });
draws.push({ prim: "sphere", pos: [0, bodyY + 0.4, 0], scale: 0.8, color: ratBodyColor });

draws.push({ prim: "sphere", pos: [-0.3, bodyY + 0.7, 0.3], scale: 0.15, color: ratEyeColor });
draws.push({ prim: "sphere", pos: [0.3, bodyY + 0.7, 0.3], scale: 0.15, color: ratEyeColor });

for (let leg = 0; leg < 4; leg++) {
    const side = leg < 2 ? -1 : 1;
    const front = leg < 2 ? 1 : -1;
    const xPos = side * 0.4;
    const zPos = front * 0.5;
    const legY = -0.4 + Math.sin(time * 1.5 + leg) * 0.05;

    draws.push({
        prim: "cylinder", pos: [xPos, legY, zPos], rot: [0, 0, Math.PI/2], scale: [0.15, 0.4, 0.15], color: [0.3, 0.3, 0.3]
    });
}

draws.push({ prim: "cone", pos: [-0.4, bodyY + 1.0, 0.6], rot: [Math.PI/2, 0, Math.PI/2], scale: [0.25, 0.25, 0.2], color: [0.2, 0.1, 0.1] });
draws.push({ prim: "cone", pos: [0.4, bodyY + 1.0, 0.6], rot: [-Math.PI/2, 0, Math.PI/2], scale: [0.25, 0.25, 0.2], color: [0.2, 0.1, 0.1] });

for (let i = 0; i < 8; i++) {
    const offsetX = (i % 2 === 0 ? -1 : 1) * (0.5 + Math.random() * 1.5);
    const offsetZ = (Math.random() - 0.5) * 4.0;
    const offsetY = -0.5 + Math.random() * 0.5;
    const speed = 0.2 + Math.random() * 0.3;
