fragBody:
vec3 n = normalize(v_normal);
vec3 lightDir = normalize(vec3(1.0, 1.5, 1.0));
float diff = max(dot(n, lightDir), 0.0);

// Base toon shading steps
float r1 = step(0.2, diff) * 0.2;
float r2 = step(0.5, diff) * 0.3;
float r3 = step(0.8, diff) * 0.4;
float baseLight = r1 + r2 + r3;

vec3 shaded = v_baseColor * (0.4 + baseLight);

// Fresnel rim light for definition
vec3 viewDir = normalize(vec3(0.0) - v_worldPos);
float fresnel = pow(1.0 - max(dot(n, viewDir), 0.0), 3.0);
shaded += fresnel * vec3(0.8, 0.8, 0.9);

// Procedural outline simulation using depth/position variance
float posDist = length(v_worldPos);
float outlineStrength = smoothstep(0.98, 1.02, posDist) * 0.3; // Very subtle edge
// Or simpler: hard outline if normal is perpendicular to view
float edge = smoothstep(0.95, 1.0, abs(dot(n, viewDir)));
shaded -= edge * 0.25;

fragColor = vec4(shaded, 1.0);

