    const angle = (i / numVertebrae) * Math.PI * 2;
    const x = Math.cos(angle) * ringRadius;
    const z = Math.sin(angle) * ringRadius;

    // Spine segment
    state.draws.push({
        prim: "cylinder",
        pos: [x, 0, z],
        rot: [Math.PI/2, 0, angle],
        scale: [0.4, 1.5, 0.4],
        color: [0.95, 0.93, 0.85] // Bone white
