    state.draws.push({
        prim: "cone",
        pos: [x, 0, z],
        rot: [Math.PI, 0, angle],
        scale: [0.2, 0.6, 0.2],
        color: [0.85, 0.8, 0.7]
    });
}

// Hour Hand (Femur + Tibia)
