fragBody:
vec3 n = normalize(v_normal);
vec3 lightDir = normalize(vec3(0.5, 1.0, 0.8));
vec3 viewDir = normalize(-v_worldPos);

// Base diffuse lighting
float diff = max(dot(n, lightDir), 0.0);

// Specular highlight (Phong)
vec3 reflectDir = reflect(-lightDir, n);
float spec = pow(max(dot(viewDir, reflectDir), 0.0), 64.0);

// Fresnel rim for organic feel
float rim = pow(1.0 - max(dot(n, viewDir), 0.0), 2.0);

// Organic pulsing based on world position height
float pulse = sin(u_time * 2.0 + v_worldPos.y * 3.0) * 0.1 + 0.5;
pulse = clamp(pulse, 0.2, 0.9);

// Material differentiation based on color channels
float isMetal = max(max(v_baseColor.r, v_baseColor.g), v_baseColor.b); // Brass is high value
float isGlass = abs(v_baseColor.r - v_baseColor.g); // Vials are distinct

vec3 finalColor = vec3(0.0);

if (isMetal > 0.8) {
    // Brass/Metal style
    finalColor = v_baseColor * (diff * 0.6 + spec * 2.0);
    finalColor += vec3(0.1, 0.05, 0.0) * 0.5; // Ambient warm tint
} else if (isGlass > 0.3) {
    // Glass style
    finalColor = v_baseColor * (diff * 0.4 + rim * 0.8);
    finalColor += vec3(0.2, 0.6, 0.8) * 0.1; // Blue tint
} else {
    // Organic/Coral style
    vec3 tint = v_baseColor * pulse;
    finalColor = tint * (diff + 0.1);
    finalColor += vec3(1.0, 0.6, 0.4) * rim * 0.5;

    // Veining pattern
    float noise = sin(v_worldPos.x * 20.0) * sin(v_worldPos.z * 20.0);
    finalColor += v_baseColor * noise * 0.05;
}

fragColor = vec4(finalColor, 1.0);

