fragBody:
vec3 n = normalize(v_normal);
vec3 base = v_baseColor;
vec3 pos = v_worldPos;

// Wireframe calculation based on angle change
float angle = atan(pos.y, pos.x);
float dist = length(pos);

// Calculate a subtle grid based on world position
vec2 grid = abs(fract(pos.xy * 5.0) - 0.5);
float wire = step(0.48, grid.x) + step(0.48, grid.y);
wire = clamp(wire, 0.0, 1.0);

// Boiling effect inside the still
float boil = sin(pos.z * 10.0 + u_time * 5.0) * 0.5 + 0.5;

// Combine base color with wireframe and boil
vec3 finalColor = mix(base, vec3(0.0), wire * 0.4);
finalColor += base * boil * 0.3;

// Add a glowing rim based on normal
float rim = 1.0 - max(dot(n, vec3(0.0, 0.0, 1.0)), 0.0);
finalColor += vec3(0.8, 0.6, 0.4) * pow(rim, 3.0) * 0.5;

// Time-based flicker for the liquid
finalColor = mix(finalColor, finalColor * 0.8, sin(u_time * 3.0 + pos.y * 2.0) * 0.1);

fragColor = vec4(finalColor, 1.0);

