float isLiquid = step(0.3, dot(v_baseColor, vec3(1.0, 0.8, 0.0)));

vec3 baseMat = mix(copper, glass, isGlass);
baseMat = mix(baseMat, liquid, isLiquid);

vec3 litColor = baseMat * intensity + vec3(0.1, 0.1, 0.1) * fresnel;

litColor += vec3(0.2, 0.1, 0.0) * fresnel * 2.0;

if (isGlass > 0.5) {
    litColor += vec3(0.0, 0.2, 0.4) * (1.0 - diff);
}

fragColor = vec4(litColor, 1.0);

