// Alternating thick and thin segments to look like a segmented spine
for (let i = 0; i < segments; i++) {
    let y = -1.5 + (i / segments) * keyLength;
    let isThick = (i % 3 === 0);
    let radius = isThick ? 0.4 : 0.25;
    let length = 0.6;

    // Color gradient: Rusty at bottom, Brass at top (inverted for y-axis)
    let tVal = i / segments;
    let r = 0.4 + (0.6 * (1.0 - tVal));
    let g = 0.2 + (0.6 * (1.0 - tVal));
    let b = 0.1 + (0.3 * (1.0 - tVal));

    draws.push({
        prim: "cylinder",
        pos: [0, y, 0],
        scale: [radius, length, radius],
        color: [r, g, b]
    });
}

// Build the Key Bow (The handle/head) - Top part
// A large torus ring
draws.push({
    prim: "torus",
    pos: [0, 0, 0],
    rot: [0, 0, 0],
    scale: 1.2,
    color: [0.3, 0.1, 0.05] // Darker rust at the very top
});

