draws.push({
    prim: "cylinder",
    pos: [0, 0.2, 0],
    scale: 0.6,
    color: [0.3, 0.1, 0.05]
});

// The Bit (The jagged part at the bottom)
// Constructed from small cubes offset to the side
let bitY = -3.0 - keyLength/2;
for (let j = 0; j < 4; j++) {
    let offset = j % 2 === 0 ? 0.3 : -0.3;
    draws.push({
        prim: "cube",
        pos: [offset, bitY + j * 0.4, 0],
        scale: 0.6,
        color: [0.9, 0.8, 0.6] // Bright brass at the working end
    });
}

// Rotate the entire key slowly on Y axis, and wobble on X
// We achieve this by rotating the "camera" relative to the key, 
// but since we can't group primitives easily, we simulate rotation 
// by calculating a rotation matrix for the camera or just letting the 
// default orbit handle the view. 
// To animate the object itself, we would need to push rotated primitives.
// However, the prompt says "orbiting camera". Let's add a slow self-rotation 
// by pushing rotated versions of a few "spark" particles around the key.

for (let k = 0; k < 10; k++) {
    let angle = (time * 0.5) + (k * (Math.PI * 2 / 10));
    let r = 2.0 + Math.sin(time * 2.0) * 0.5;
    let x = Math.cos(angle) * r;
    let z = Math.sin(angle) * r;

    draws.push({
        prim: "cube",
        pos: [x, 0, z],
        scale: 0.3,
        color: [0.0, 0.5, 1.0] // Ethereal blue spark
    });
}

