    const angle = (i / petalCount) * Math.PI * 2;
    const nextAngle = ((i + 1) / petalCount) * Math.PI * 2;
    const midAngle = angle + (nextAngle - angle) / 2;

    // The "Hypergaussian" shape is simulated by a series of thin tapered segments 
    // approximating the mathematical width profile.
    const segments = 12;
    for (let s = 0; s < segments; s++) {
        const t_seg = s / segments;
        const radialDist = innerRadius + (outerRadius - innerRadius) * t_seg;

        // Hypergaussian width profile: w(r) = exp(-r^2)
        // We scale the width of the petal segment based on its distance from the center
        const widthFactor = Math.exp(-Math.pow(t_seg - 0.5, 2) * 4.0) * 0.4;
        const currentWidth = (radialDist * 0.5) * widthFactor;

        const px = Math.cos(midAngle) * radialDist;
        const py = Math.sin(midAngle) * radialDist;

        // We use thin cylinders to build the "mass" of the petal
        state.draws.push({
            prim: "cylinder",
            pos: [px, py, 0],
            rot: [Math.PI / 2, 0, angle],
            scale: [currentWidth, (outerRadius - innerRadius) / segments, petalDepth],
            color: [0.2, 0.4, 0.6]
        });
    }

    // Add a structural "spine" to each petal for visual definition
    state.draws.push({
        prim: "cylinder",
        pos: [Math.cos(angle) * (innerRadius + outerRadius) / 2, Math.sin(angle) * (innerRadius + outerRadius) / 2, 0],
        rot: [Math.PI / 2, 0, angle],
        scale: [0.02, (outerRadius - innerRadius), 0.02],
